public String alarmClock(int day, boolean vacation) {
    String alarmTime = "";

    if (vacation) {
        if (day >= 1 && day <= 5) {
            alarmTime = "10:00";
        } else {
            alarmTime = "off";
        }
    } else {
        if (day >= 1 && day <= 5) {
            alarmTime = "7:00";
        } else {
            alarmTime = "10:00";
        }
    }

    return alarmTime;
}

